    <style>
        .map-dashboard{--card:#fff;--muted:#8b99ad;--line:#e8edf5;--blue:#2d80ff;--green:#4caf50;--orange:#ffa52d;--red:#ef5350}.map-intro{border-radius:14px;background:linear-gradient(135deg,#eef4ff 0%,#f8fbff 100%);padding:18px;box-shadow:0 10px 28px rgba(31,54,86,.04)}.map-stat{border:1px solid rgba(232,237,245,.7);border-radius:14px;background:#fff;padding:16px;box-shadow:0 14px 38px rgba(31,54,86,.06)}.map-stat small{color:var(--muted)}.map-stat h4{margin:6px 0 0}.map-workspace{display:grid;grid-template-columns:390px minmax(520px,1fr);gap:14px;min-height:680px}.project-panel,.map-panel{background:#fff;border:1px solid rgba(232,237,245,.7);border-radius:14px;box-shadow:0 14px 38px rgba(31,54,86,.06);overflow:hidden}.project-list{height:520px;overflow:auto;padding:12px;display:grid;gap:10px;align-content:start}.project-card{display:grid;grid-template-columns:82px 1fr;gap:10px;border:1px solid #e8edf5;border-radius:12px;padding:9px;cursor:pointer;transition:.18s}.project-card:hover,.project-card.active{border-color:#b8d5ff;box-shadow:0 10px 22px rgba(45,128,255,.07);transform:translateY(-1px)}.project-photo{width:82px;height:82px;border-radius:10px;object-fit:cover;background:#f6f9fd}.card-slider{position:relative;width:82px;height:82px}.card-slider img{width:82px;height:82px;border-radius:10px;object-fit:cover;background:#f6f9fd}.map-slider{position:relative}.map-slider img{width:100%;height:100px;object-fit:cover;border-radius:9px;border:1px solid #e2e9f2;margin-bottom:9px;background:#f6f9fd}.slider-btn{position:absolute;top:50%;transform:translateY(-50%);width:24px;height:24px;border:0;border-radius:50%;background:rgba(31,54,86,.75);color:#fff;font-size:14px;display:grid;place-items:center}.slider-btn.prev{left:5px}.slider-btn.next{right:5px}.slider-dots{position:absolute;left:0;right:0;bottom:12px;display:flex;justify-content:center;gap:4px}.slider-dots i{width:5px;height:5px;border-radius:50%;background:rgba(255,255,255,.72)}.project-title{font-size:13px;color:#324052;font-weight:600;line-height:1.25}.project-meta{font-size:11px;color:var(--muted)}.status-tag{border-radius:6px;padding:3px 7px;font-size:10px;font-weight:700;white-space:nowrap}.status-en-ejecucion{color:#138f51;background:#e7fbef}.status-finalizado{color:#2d80ff;background:#e7f1ff}.status-planificacion,.status-licitacion{color:#d28400;background:#fff3da}.status-pausado{color:#d43f3a;background:#fff0ef}#projectMap{width:100%;height:100%;min-height:680px;background:#e9eff7}.map-panel{position:relative}.map-legend{position:absolute;z-index:510;left:14px;bottom:14px;display:flex;gap:10px;flex-wrap:wrap;background:rgba(255,255,255,.94);border:1px solid #e5ebf3;border-radius:10px;box-shadow:0 10px 26px rgba(31,54,86,.08);padding:9px 10px;color:#707d90;font-size:11px}.dot{width:8px;height:8px;display:inline-block;border-radius:50%;margin-right:5px}.popup-photo{width:100%;height:100px;object-fit:cover;border-radius:9px;border:1px solid #e2e9f2;margin-bottom:9px;background:#f6f9fd}.popup-title{font-size:13px;font-weight:700;margin-bottom:6px}.popup-progress{height:7px;background:#edf2f7;border-radius:999px;overflow:hidden;margin:9px 0}.popup-progress span{display:block;height:100%;background:linear-gradient(90deg,#58d9c7,#2d80ff)}@media(max-width:1100px){.map-workspace{grid-template-columns:1fr}.project-list{height:auto;max-height:520px}#projectMap{height:620px}}
