<body><div class="wrapper"><?php include('partials/menu.php'); ?><div class="content-page"><div class="container-fluid map-dashboard">
<?php $subtitle='Mapa comunal'; $title='Panel de proyectos'; include('partials/page-title.php'); ?>
<div class="map-intro mb-3 d-flex flex-wrap justify-content-between gap-2"><div><h5 class="mb-1">Mapa municipal de inversión y obras</h5><p class="text-muted mb-0">Visualización territorial de proyectos registrados, en ejecución y en planificación.</p></div><div class="d-flex align-items-center gap-2"><a class="btn btn-primary" href="proyectos-mapa.php">Registrar proyecto</a><button class="btn btn-outline-secondary" onclick="window.print()">Imprimir</button></div></div>
<div class="row g-3 mb-3"><div class="col-md-3"><div class="map-stat"><small>Proyectos registrados</small><h4 id="metricTotal">0</h4></div></div><div class="col-md-3"><div class="map-stat"><small>Financiamiento total</small><h4 id="metricInvestment">$0</h4></div></div><div class="col-md-3"><div class="map-stat"><small>En ejecución</small><h4 id="metricActive">0</h4></div></div><div class="col-md-3"><div class="map-stat"><small>Avance promedio</small><h4 id="metricProgress">0%</h4></div></div></div>
<section class="map-workspace"><aside class="project-panel"><div class="p-3 border-bottom d-flex justify-content-between"><strong>Proyectos visibles</strong><span id="resultCount" class="text-muted">0 resultados</span></div><div class="p-3 border-bottom"><input id="searchInput" type="search" class="form-control mb-2" placeholder="Buscar nombre, estado o financiamiento"><div class="row g-2"><div class="col-6"><select id="statusFilter" class="form-select"><option value="">Todos los estados</option><option>En ejecución</option><option>Finalizado</option><option>Planificación</option><option>Licitación</option><option>Pausado</option></select></div><div class="col-6"><select id="stageFilter" class="form-select"><option value="">Todas las etapas</option><option>Diseño</option><option>Licitación</option><option>Construcción</option><option>Recepción</option><option>Operación</option><option>Convenio</option></select></div></div></div><div class="project-list" id="projectList"></div></aside><section class="map-panel"><div id="projectMap"></div><div class="map-legend"><span><i class="dot" style="background:#4caf50"></i> En ejecución</span><span><i class="dot" style="background:#2d80ff"></i> Finalizado</span><span><i class="dot" style="background:#ffa52d"></i> Planificación / Licitación</span><span><i class="dot" style="background:#ef5350"></i> Pausado</span></div></section></section>
</div><?php include('partials/footer.php'); ?></div></div><?php include('partials/customizer.php'); ?><?php include('partials/footer-scripts.php'); ?><script src="assets/plugins/leaflet/leaflet.js"></script><script>
const projects=<?php echo $projectsJson ?: '[]'; ?>;
const fallbackPhoto='assets/images/logo.png';
const map=L.map('projectMap').setView([-20.2595,-69.7863],13);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{maxZoom:19,attribution:'&copy; OpenStreetMap'}).addTo(map);
const markers=new Map();const list=document.getElementById('projectList');
function slug(v){return (v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/\s+/g,'-');}
function moneyToNumber(v){return Number(String(v||'').replace(/[^0-9]/g,''))||0;}
function markerColor(status){return {'En ejecución':'#4caf50','Finalizado':'#2d80ff','Pausado':'#ef5350'}[status]||'#ffa52d';}
function icon(status){const c=markerColor(status);return L.divIcon({className:'',html:`<span style="display:block;width:18px;height:18px;border-radius:50%;background:${c};border:3px solid #fff;box-shadow:0 4px 12px #0003"></span>`,iconSize:[18,18],iconAnchor:[9,9]});}
function getPhotos(p){try{const parsed=JSON.parse(p.fotos||'[]');if(Array.isArray(parsed)&&parsed.length){return parsed;}}catch(e){}return p.foto?[p.foto]:[fallbackPhoto];}
function sliderHtml(p, cls){const photos=getPhotos(p);const controls=photos.length>1?`<button class="slider-btn prev" data-slider-dir="-1" type="button">‹</button><button class="slider-btn next" data-slider-dir="1" type="button">›</button><span class="slider-dots">${photos.map(()=>'<i></i>').join('')}</span>`:'';return `<span class="${cls}" data-slider-index="0" data-photos="${encodeURIComponent(JSON.stringify(photos))}"><img src="${photos[0]||fallbackPhoto}" alt="">${controls}</span>`;}
function popup(p){return `${sliderHtml(p,'map-slider')}<div class="popup-title">${p.nombre}</div><div class="text-muted small"><b>Estado:</b> ${p.estado}<br><b>Etapa:</b> ${p.etapa}<br><b>Monto:</b> ${p.monto||'-'}<br><b>Financiamiento:</b> ${p.financiamiento||'-'}</div><div class="popup-progress"><span style="width:${Number(p.avance)||0}%"></span></div><div class="small text-muted">${p.descripcion||''}</div>`;}
function card(p){return `<article class="project-card" data-id="${p.id}">${sliderHtml(p,'card-slider')}<div><div class="d-flex justify-content-between gap-2 mb-1"><div class="project-title">${p.nombre}</div><span class="status-tag status-${slug(p.estado)}">${p.estado}</span></div><div class="project-meta"><b>Etapa:</b> ${p.etapa}<br><b>Sector:</b> ${p.sector||'-'}<br><b>Monto:</b> ${p.monto||'-'}<br><b>Avance:</b> ${p.avance||0}%</div></div></article>`;}
function filtered(){const q=document.getElementById('searchInput').value.toLowerCase();const status=document.getElementById('statusFilter').value;const stage=document.getElementById('stageFilter').value;return projects.filter(p=>(!status||p.estado===status)&&(!stage||p.etapa===stage)&&[p.nombre,p.estado,p.etapa,p.sector,p.financiamiento].join(' ').toLowerCase().includes(q));}
function render(){markers.forEach(m=>map.removeLayer(m));markers.clear();const data=filtered();list.innerHTML=data.length?data.map(card).join(''):'<div class="text-center text-muted p-4">No hay proyectos para los filtros seleccionados.</div>';data.forEach(p=>{const m=L.marker([Number(p.lat),Number(p.lng)],{icon:icon(p.estado)}).addTo(map).bindPopup(popup(p));markers.set(String(p.id),m);});if(data.length){map.fitBounds(data.map(p=>[Number(p.lat),Number(p.lng)]),{padding:[40,40],maxZoom:15});}document.getElementById('resultCount').textContent=`${data.length} resultados`;document.getElementById('metricTotal').textContent=data.length;document.getElementById('metricActive').textContent=data.filter(p=>p.estado==='En ejecución').length;document.getElementById('metricInvestment').textContent=new Intl.NumberFormat('es-CL',{style:'currency',currency:'CLP',maximumFractionDigits:0}).format(data.reduce((s,p)=>s+moneyToNumber(p.monto),0));document.getElementById('metricProgress').textContent=(data.length?Math.round(data.reduce((s,p)=>s+(Number(p.avance)||0),0)/data.length):0)+'%';}
document.addEventListener('click',e=>{const btn=e.target.closest('[data-slider-dir]');if(!btn)return;e.preventDefault();e.stopPropagation();const slider=btn.closest('[data-photos]');const photos=JSON.parse(decodeURIComponent(slider.dataset.photos||'%5B%5D'));if(!photos.length)return;let index=Number(slider.dataset.sliderIndex||0);index=(index+Number(btn.dataset.sliderDir)+photos.length)%photos.length;slider.dataset.sliderIndex=String(index);slider.querySelector('img').src=photos[index];});
list.addEventListener('click',e=>{const el=e.target.closest('.project-card');if(!el)return;document.querySelectorAll('.project-card').forEach(x=>x.classList.remove('active'));el.classList.add('active');const m=markers.get(el.dataset.id);if(m){map.setView(m.getLatLng(),16);m.openPopup();}});['searchInput','statusFilter','stageFilter'].forEach(id=>document.getElementById(id).addEventListener('input',render));render();
</script></body></html>
